import React, { useState } from 'react';
import axios from 'axios';
import MapDisplay from './components/MapDisplay';
import SafetyIndicators from './components/SafetyIndicators';
import SOSButton from './components/SOSButton';
import './App.css';
import { MapPinIcon, MagnifyingGlassIcon } from '@heroicons/react/24/solid';

function App() {
  const [source, setSource] = useState('');
  const [destination, setDestination] = useState('');
  const [sourceCoords, setSourceCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [routeFound, setRouteFound] = useState(false);
  const [loading, setLoading] = useState(false);
  const [safeWaypoints, setSafeWaypoints] = useState([]);

  const geocode = async (place) => {
    const res = await axios.get(`https://nominatim.openstreetmap.org/search`, {
      params: { q: place, format: 'json', limit: 1 },
    });
    if (res.data.length > 0) {
      return { lat: parseFloat(res.data[0].lat), lng: parseFloat(res.data[0].lon) };
    }
    return null;
  };

  const handleFindRoute = async () => {
    if (!source.trim() || !destination.trim()) return alert('Please enter both locations');
    setLoading(true);

    try {
      const src = await geocode(source);
      const dest = await geocode(destination);

      if (!src || !dest) {
        setLoading(false);
        return alert('Could not find coordinates for these locations.');
      }

      setSourceCoords(src);
      setDestinationCoords(dest);

      const response = await axios.post('http://localhost:3002/getSafeRoute', {
        source: src,
        destination: dest
      });

      const waypoints = response.data.waypoints || [src, dest];
      
      setSafeWaypoints(waypoints);
      setRouteFound(true);

    } catch (error) {
      console.error("Error calculating safe route:", error);
      alert("Backend routing failed. Is your backend running on port 3002?");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full bg-gray-100 font-sans">
      
      {/* Background Map */}
      <div className="absolute inset-0 z-0">
         <MapDisplay waypoints={safeWaypoints} /> 
      </div>

      {/* Floating UI Card - Upgraded for more attractiveness */}
      <div className="absolute top-4 left-4 sm:top-8 sm:left-8 z-10 w-[calc(100%-2rem)] sm:w-full max-w-md">
        <div className="bg-white/85 backdrop-blur-xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] rounded-3xl p-6 sm:p-8 border border-white/50">
          
          {/* ========================================== */}
          {/* LOGO AND BRANDING SECTION                  */}
          {/* ========================================== */}
          <div className="flex items-center space-x-4 mb-8 p-3 bg-gradient-to-r from-purple-50/50 to-pink-50/50 rounded-2xl border border-purple-100 shadow-sm">
            
            {/* The Logo Container with Glowing Highlight */}
            <div className="relative flex-shrink-0 group cursor-pointer">
              {/* Animated glowing blur behind the logo */}
              <div className="absolute -inset-1 bg-gradient-to-r from-purple-600 to-pink-600 rounded-full blur opacity-40 group-hover:opacity-75 transition duration-500 animate-pulse"></div>
              
              {/* Your Actual Logo Image */}
              <img
                src="/ogo.jpeg" // <-- Put your logo in the public folder and name it sheroute-logo.png
                alt="Logo"
                className="relative h-16 w-16 rounded-full object-cover border-2 border-white shadow-md bg-white p-1"
                onError={(e) => {
                  // This is a temporary placeholder if your image isn't found yet!
                  e.target.src = 'https://ui-avatars.com/api/?name=SR&background=a855f7&color=fff&rounded=true&bold=true&size=128';
                }}
              />
            </div>

            <div>
              <h1 className="text-3xl font-extrabold bg-gradient-to-r from-purple-700 to-pink-600 bg-clip-text text-transparent drop-shadow-sm">
                SheRoute
              </h1>
              <p className="text-sm text-gray-500 font-medium tracking-wide">Navigating Safety Together</p>
            </div>
          </div>
          {/* ========================================== */}
          
          <div className="space-y-5">
            <div className="relative group">
              <MapPinIcon className="absolute left-4 top-3.5 h-5 w-5 text-gray-400 group-focus-within:text-purple-500 transition-colors" />
              <input
                type="text"
                placeholder="Where are you right now?"
                value={source}
                onChange={(e) => setSource(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-gray-50/80 border border-gray-200 rounded-2xl focus:bg-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all shadow-inner font-medium text-gray-700 placeholder-gray-400"
              />
            </div>

            <div className="relative group">
              <MapPinIcon className="absolute left-4 top-3.5 h-5 w-5 text-pink-500" />
              <input
                type="text"
                placeholder="Where do you want to go?"
                value={destination}
                onChange={(e) => setDestination(e.target.value)}
                className="w-full pl-12 pr-4 py-3.5 bg-gray-50/80 border border-gray-200 rounded-2xl focus:bg-white focus:ring-2 focus:ring-pink-500 focus:border-transparent outline-none transition-all shadow-inner font-medium text-gray-700 placeholder-gray-400"
              />
            </div>

            <button
              onClick={handleFindRoute}
              disabled={loading}
              className="w-full flex items-center justify-center space-x-2 bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700 text-white font-bold py-4 px-4 rounded-2xl shadow-[0_4px_14px_0_rgb(168,85,247,0.39)] hover:shadow-[0_6px_20px_rgba(168,85,247,0.23)] hover:-translate-y-0.5 transform transition-all active:scale-95"
            >
              <MagnifyingGlassIcon className="h-6 w-6" />
              <span className="text-lg">{loading ? 'Calculating Route...' : 'Find Safe Route'}</span>
            </button>
          </div>

          {routeFound && (
            <div className="mt-6 pt-6 border-t border-gray-200/60">
               <SafetyIndicators />
            </div>
          )}
        </div>
      </div>

      <SOSButton />
    </div>
  );
}

export default App;
